INSERT INTO theses VALUES(1,'NVDA','2026-05-11T05:24:48.425236+00:00',4,'long','24m','["AI capex hyperscaler continue >40% YoY", "HBM supply contrainte 2026-2027", "CUDA moat 18-24 mois", "ASIC alternative pas mature avant 2027"]','["revenue growth Q/Q sous 25% deux trim consecutifs", "perte d''un hyperscaler key account", "emergence ASIC avec >30% market share AI training", "revenue concentration top-5 > 70%"]',130.0,250.0,170.0,NULL,NULL,NULL,NULL,NULL,NULL,'deleted','2026-05-15T15:24:10.202147','DUMMY TEST artifact from Phase 2 marathon (2026-05-11). Soft-deleted 2026-05-15 once real sector theses logged. Audit trail preserved (status=''deleted'', not DELETE FROM). Predictions linked to this thesis (signal_id=NVDA early dummy) remain intact for their own resolution lifecycle.','["price >= 250", "insider_net_90d <= -250M sustained 30d", "clv_30d < -15%"]',250.0,400.0,'2026-05-11T05:24:48.425236+00:00',NULL,NULL,NULL,235.5,'2026-05-14T18:15:00','{"failure_modes": [{"scenario": "Hyperscaler capex digestion in H2 2025: Microsoft, Meta and Google guide flat to -10% AI capex for 2026 after building out 2024-2025, citing utilization gaps and Blackwell inventory absorption. NVDA data center revenue decelerates from +90% YoY to sub-20% in two quarters, multiple compresses from 35x to 22x forward.", "probability": 0.28, "signals_to_monitor": ["MSFT/META/GOOGL quarterly capex guidance revisions", "Blackwell lead times shrinking below 8 weeks", "hyperscaler GPU utilization commentary on earnings calls"], "mitigation": "Trim 40% on first hyperscaler guide-down; full exit if second hyperscaler confirms digestion narrative within 90 days"}, {"scenario": "Custom ASIC adoption accelerates faster than expected: Google TPU v6, AWS Trainium 3, and Meta MTIA v2 capture meaningful inference workloads in 2025, with Broadcom AI revenue scaling past $20B. Hyperscalers publicly reallocate 30-40% of incremental AI spend to internal silicon, compressing NVDA''s share of AI accelerator TAM.", "probability": 0.22, "signals_to_monitor": ["AVGO and MRVL custom silicon revenue trajectory", "hyperscaler disclosures on internal vs merchant silicon mix", "PyTorch/JAX native ASIC support maturity"], "mitigation": "Cut position by half if AVGO AI revenue grows >80% YoY two quarters in a row while NVDA decelerates"}, {"scenario": "China export control escalation: US tightens to ban H20 and successor chips entirely, China retaliates with rare earth or HBM-related restrictions. NVDA loses $12-17B annualized China revenue with no offset, and Huawei Ascend 910C captures domestic share permanently.", "probability": 0.18, "signals_to_monitor": ["BIS rulemaking on AI chip export thresholds", "Huawei Ascend production volume leaks", "NVDA China revenue % in 10-Q"], "mitigation": "Hedge with SOXX puts or pair-trade short on any BIS announcement; reassess thesis if China <5% of revenue"}, {"scenario": "HBM oversupply instead of shortage: Samsung qualifies HBM3E with NVDA in 2025, joining SK Hynix and Micron. Combined supply growth of 200%+ outpaces demand as inference shifts to lower-memory architectures, eliminating the pricing power tailwind and compressing gross margins from 75% toward 68%.", "probability": 0.15, "signals_to_monitor": ["Samsung HBM3E qualification status with NVDA", "SK Hynix HBM capacity expansion announcements", "NVDA gross margin guidance trajectory"], "mitigation": "Reduce position if NVDA guides GM below 72% for two consecutive quarters"}, {"scenario": "Model scaling laws break / inference efficiency leap: A DeepSeek-style efficiency breakthrough (10x compute reduction for equivalent capability) becomes mainstream, or GPT-5/Claude successors show diminishing returns from compute scaling. Frontier labs cut training cluster orders, and the ''more GPUs = better models'' narrative breaks.", "probability": 0.12, "signals_to_monitor": ["OpenAI/Anthropic next-gen model benchmark gains vs compute used", "open-source model efficiency improvements", "training run sizes disclosed in research papers"], "mitigation": "Immediate 50% trim on any major efficiency paper with industry adoption; reassess long-term TAM"}], "overall_assessment": "The single biggest fragility is concentration risk on hyperscaler capex cycle: ~50% of revenue comes from 4-5 customers whose 2026 spending plans are simultaneously decided in mid-2025, making NVDA a leveraged bet on one synchronized capital allocation decision rather than diversified AI adoption.", "asymmetry_warning": "Upside to $400 target = +208% vs stop at $170 = +31% from $130 entry, so nominal asymmetry favors the trade. However, the stop at $170 (above entry) implies the thesis requires near-immediate upward momentum; if NVDA chops between $110-160 for 12 months (plausible in a capex digestion scenario), the position bleeds opportunity cost while the stop never triggers cleanly, and a sharp gap-down on hyperscaler guidance could blow through $170 to $120 overnight, making realized downside materially worse than the stop suggests."}');
INSERT INTO theses VALUES(2,'4063.T','2026-05-15T15:02:57.229933',4,'watch','365d','["Shin-Etsu = wafer #1 (~30% PDM) + Shin-Etsu Quartz Products vertical (crucibles)", "Beneficiary direct chokepoint HPQ", "P/E ~17x, pure picks-and-shovels japonais classique", "Sector: chaine HPQ -> crucibles -> wafers Si 300mm = oligopole <=5 acteurs irreplacable"]','["Synthetic HPQ scale >20% market share natural", "China atteint qualification semi-grade HPQ domestique", "Hyperscaler capex cycle deceleration suffisamment forte pour casser pricing power upstream (DeepSeek scenario)"]',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'superseded','2026-05-16 17:02:41',unistr('sector_thesis_id: HPQ_WAFER_CHOKEPOINT_2026\u000asector_role: implementation: wafer #1 + vertical crucibles\u000apre_mortem: Risk principal: marche commence a pricer la decote en 2026 avant qu''on en beneficie. Risk secondaire: technology shift (advanced packaging, chiplets, photonic interconnects) reduit demand wafer growth structurellement. | superseded by full thesis logging 2026-05-16'),NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-05-15T18:30:00',NULL);
